  ('real-estate-moex-01391', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '有關土地法及平均地權條例規定照價收買之時機，下列何者正確？', '["所有權人申報地價未達公告現值之百分之八十時", "荒地限期使用並經加徵荒地稅滿2年後仍不使用者", "土地所有權人認為標準地價過高，不能為其百分之二十以內增減之申報時，得聲請該管直轄市或縣（市） 政府照價收買", "私有土地超過最高限額限期1年未出售或使用者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
